import os
from kafka import AdminClient
from kafka.structs import TopicPartition
from argparse import ArgumentParser

def create_topic(admin_client, topic_name):
    try:
        admin_client.create_topics(new_topics=[(topic_name, {'num_partitions': 1})])
        print(f"Topic {topic_name} created successfully.")
    except Exception as e:
        print(f"Failed to create topic {topic_name}: {str(e)}")

def delete_topic(admin_client, topic_name):
    try:
        admin_client.delete_topics([topic_name])
        print(f"Topic {topic_name} deleted successfully.")
    except Exception as e:
        print(f"Failed to delete topic {topic_name}: {str(e)}")

def describe_topic(admin_client, topic_name):
    try:
        topic = admin_client.describe_topics([topic_name])[0]
        print(f"Topic {topic_name} description: {topic}")
    except Exception as e:
        print(f"Failed to get topic description for {topic_name}: {str(e)}")

def alter_config(admin_client, topic_name, config):
    try:
        admin_client.alter_topics(new_configs={topic_name: config})
        print(f"Config altered for topic {topic_name} successfully.")
    except Exception as e:
        print(f"Failed to alter config for topic {topic_name}: {str(e)}")

def main():
    parser = ArgumentParser()
    parser.add_argument('--bootstrap_servers', required=True, help='Kafka bootstrap servers')
    parser.add_argument('--topic', required=True, help='Topic name')
    parser.add_argument('--action', choices=['create', 'delete', 'describe', 'alter'], required=True, help='Action to perform on topic')
    parser.add_argument('--config', nargs='+', help='Config key-value pairs for altering topic config')
    args = parser.parse_args()

    if not os.path.exists('/etc/kafka/secrets'):
        print("Kafka admin credentials file '/etc/kafka/secrets' does not exist.")
        return

    with open('/etc/kafka/secrets', 'r') as f:
        kafka_admin_credentials = f.read().splitlines()
        bootstrap_servers, username, password = kafka_admin_credentials

    admin_client = AdminClient({
        'bootstrap.servers': bootstrap_servers,
        'security.protocol': 'SSL',
        'ssl.key.location': '/etc/kafka/secrets/kafka.server.key',
        'ssl.certificate.location': '/etc/kafka/secrets/kafka.server.cert',
        'ssl.truststore.location': '/etc/kafka/secrets/truststore.jks',
        'ssl.truststore.password': password,
        'ssl.keystore.location': '/etc/kafka/secrets/keystore.jks',
        'ssl.keystore.password': password
    })

    if args.action == 'create':
        create_topic(admin_client, args.topic)
    elif args.action == 'delete':
        delete_topic(admin_client, args.topic)
    elif args.action == 'describe':
        describe_topic(admin_client, args.topic)
    elif args.action == 'alter':
        config = {}
        for i in range(0, len(args.config), 2):
            key, value = args.config[i], args.config[i+1]
            config[key] = value
        alter_config(admin_client, args.topic, config)

if __name__ == "__main__":
    main()